#include<bits/stdc++.h>
using namespace std;
int n,m,a[100010];
vector<int> p[100010];
void dfs(int x,int v){
    if(a[x])return; 
	a[x]=v;for(int i=0;i<p[x].size();i++)dfs(p[x][i],v);
}
int main(void){
    cin>>n>>m;
    for(int i=1;i<=m;i++){int u,v;cin>>u>>v,p[v].push_back(u);}
    for(int i=n;i;i--)if(!a[i])dfs(i,i);
    for(int i=1;i<=n;i++)cout<<a[i]<<' ';
    return false;
}
